select
  null,
  'rescisao',
  'Rescisão imotivada com aviso prévio',
  'Qualquer das partes poderá rescindir o presente contrato sem motivação, mediante aviso prévio por escrito de 30 (trinta) dias à outra parte, sem que tal rescisão implique qualquer indenização adicional, salvo o pagamento dos valores devidos até a data efetiva da rescisão.',
  array['service_agreement', 'supply']::text[],
