select
  null,
  'confidencialidade',
  'Sigilo e confidencialidade',
  'As partes obrigam-se a manter em absoluto sigilo todas as informações confidenciais, comerciais, técnicas, operacionais ou financeiras a que tiverem acesso em razão do presente contrato, durante sua vigência e pelo prazo de 5 (cinco) anos após sua extinção, sob pena de responder por perdas e danos.',
  array['nda', 'service_agreement', 'supply', 'employment']::text[],
