select
  null,
  'lgpd',
  'Proteção de dados pessoais (LGPD)',
  'As partes comprometem-se a tratar quaisquer dados pessoais coletados, armazenados ou processados no âmbito deste contrato em estrita observância à Lei nº 13.709/2018 (Lei Geral de Proteção de Dados Pessoais — LGPD), adotando medidas técnicas e administrativas adequadas para proteger tais dados contra acessos não autorizados, vazamentos ou uso indevido.',
