select
  null,
  'garantia',
  'Garantia de qualidade dos serviços',
  'A CONTRATADA garante a qualidade técnica dos serviços prestados, comprometendo-se a refazer, sem ônus adicional, quaisquer entregas que apresentem defeito ou não atendam às especificações acordadas, no prazo de 30 (trinta) dias após a comunicação formal da CONTRATANTE.',
