select
  null,
  'garantia_locaticia',
  'Garantia locatícia (fiança)',
  'Como garantia das obrigações decorrentes do presente contrato de locação, o LOCATÁRIO apresenta como fiador(es) [NOME_FIADOR], que assume(m) responsabilidade solidária pelo cumprimento de todas as obrigações pecuniárias do LOCATÁRIO, na qualidade de devedor(es) solidário(s), nos termos do art. 37, II da Lei nº 8.245/91.',
  array['lease']::text[],
